        /// <summary>
        /// Example 2: Create and use a Handle (the key pattern for spike 004)
        /// Demonstrates object caching via handles
        /// </summary>
        public static void Example_HandlePattern()
        {
            Console.WriteLine("=== Handle Pattern (Object Caching) ===");
            
            // This is the critical pattern for concurrent safety
            // In QuantLib SWIG, Handles are smart pointers to shared objects
            
            // Pseudo-code:
            // Handle<YieldTermStructure> curveHandle = 
            //     new Handle<YieldTermStructure>(new FlatForwardCurve(...));
            //
            // The Handle maintains a reference count
            // Multiple threads can safely hold references to the same Handle
            // The underlying curve object persists as long as any Handle references it
            
            Console.WriteLine("Creating yield curve via Handle");
            Console.WriteLine("Handle manages reference counting internally");
            Console.WriteLine("Safe for concurrent access via static cache");
        }

